import type { Context } from "hono";
import type { Env } from "../types/env.js";
import { getPrisma } from "../config/database.js";
import { serialize } from "../lib/serializer.js";

export const getClients = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const clients = await prisma.client.findMany({
      orderBy: { name: "asc" },
    });
    return c.json(serialize(clients));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const createClient = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const { name, avatar, tier, phone, email, notes } = await c.req.json();

    if (!name || !phone) {
      return c.json({ error: "Tên và Số điện thoại là bắt buộc" }, 400);
    }

    const client = await prisma.client.create({
      data: {
        name,
        avatar: avatar || `https://i.pravatar.cc/150?u=${phone}`,
        tier: tier || "Mới",
        phone,
        email: email || "",
        totalVisits: 0,
        totalSpent: 0n,
        memberPoints: 0,
        lastVisit: "Chưa có",
        joinDate: new Date().toLocaleDateString("vi-VN"),
        notes: notes || "",
      },
    });

    // Create a system notification
    await prisma.notification.create({
      data: {
        type: "info",
        title: "Khách hàng mới đăng ký",
        message: `${name} đã được thêm vào hệ thống quản lý.`,
        time: "Vừa xong",
        read: false,
        priority: "normal",
      },
    });

    return c.json(serialize(client), 201);
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};
