import type { Context } from "hono";
import type { Env } from "../types/env.js";
import { getPrisma } from "../config/database.js";
import { serialize } from "../lib/serializer.js";

export const getTherapists = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const therapists = await prisma.therapist.findMany({
      orderBy: { name: "asc" },
    });
    return c.json(serialize(therapists));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const createTherapist = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const { name, avatar, specialty, experience, bio, services } =
      await c.req.json();

    if (!name || !specialty) {
      return c.json({ error: "Tên và Chuyên môn KTV là bắt buộc" }, 400);
    }

    const therapist = await prisma.therapist.create({
      data: {
        name,
        avatar:
          avatar || `https://i.pravatar.cc/150?u=${encodeURIComponent(name)}`,
        specialty,
        experience: experience || "1 năm",
        rating: 5.0,
        totalReviews: 0,
        availability: "available",
        bio: bio || "",
        services: services || [],
      },
    });

    return c.json(serialize(therapist), 201);
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const updateTherapist = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const id = c.req.param("id");
    const { name, avatar, specialty, experience, availability, bio, services } =
      await c.req.json();

    const dbTherapist = await prisma.therapist.findUnique({ where: { id } });
    if (!dbTherapist) {
      return c.json({ error: "Nhân viên không tồn tại" }, 404);
    }

    const therapist = await prisma.therapist.update({
      where: { id },
      data: {
        name: name !== undefined ? name : undefined,
        avatar: avatar !== undefined ? avatar : undefined,
        specialty: specialty !== undefined ? specialty : undefined,
        experience: experience !== undefined ? experience : undefined,
        availability: availability !== undefined ? availability : undefined,
        bio: bio !== undefined ? bio : undefined,
        services: services !== undefined ? services : undefined,
      },
    });

    return c.json(serialize(therapist));
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};

export const deleteTherapist = async (c: Context<{ Bindings: Env }>) => {
  try {
    const prisma = getPrisma(c.env);
    const id = c.req.param("id");

    const dbTherapist = await prisma.therapist.findUnique({ where: { id } });
    if (!dbTherapist) {
      return c.json({ error: "Nhân viên không tồn tại" }, 404);
    }

    await prisma.therapist.delete({ where: { id } });

    return c.json({ success: true, message: "Đã xóa Nhân viên thành công" });
  } catch (error: any) {
    return c.json({ error: error.message }, 500);
  }
};
