import { PrismaNeonHttp } from "@prisma/adapter-neon";
import { PrismaClient } from "@prisma/client";
import type { Env } from "../types/env.js";

/**
 * Returns a Prisma Client instance using the Neon HTTP serverless driver.
 *
 * PrismaNeonHttp uses fetch() for all queries — no TCP sockets, no WebSockets.
 * This is fully compatible with Cloudflare Workers and wrangler local dev.
 *
 * Note: HTTP mode does not support interactive transactions.
 * Use prisma.$transaction([...]) (batch) instead of interactive transactions.
 */
let prismaInstance: PrismaClient | null = null;

export function getPrisma(env: Env) {
  if (!prismaInstance) {
    const adapter = new PrismaNeonHttp(env.DATABASE_URL);
    prismaInstance = new PrismaClient({ adapter });
  }
  return prismaInstance;
}
